return [
  {
    json: {
      calleConfig: {
        apiKey: "replace_with_calle_api_key",
        baseUrl: "https://api.heycall-e.com",
        pollIntervalSeconds: 5,
        waitTimeoutMinutes: 30
      }
    }
  }
];

const items = $input.all();
const config = items[0]?.json?.calleConfig || {};

if (!config.apiKey || config.apiKey === "replace_with_calle_api_key") {
  throw new Error("CALL-E API key is missing. Open the CALL-E Config node and replace apiKey before running this workflow.");
}

if (!config.baseUrl) {
  throw new Error("CALL-E baseUrl is missing. Open the CALL-E Config node and set baseUrl.");
}

return items;

const config = $input.first().json.calleConfig;

const callTasks = [
  {
    callItemId: "ivr_azul_001",
    ivrName: "Azul customer service IVR",
    phone: "+551140031118",
    region: "BR",
    locale: "pt-BR",
    task: "Call the public Azul customer service IVR in Brazil. This is an IVR quality recording sample. Do not enter personal data, do not attempt authentication, do not make purchases, and do not request a human agent. Listen to the opening IVR/menu for up to 90 seconds. Record whether the IVR connected, detected language, menu clarity, audio quality, latency, interruptions, DTMF or speech prompts, and any transfer or retry prompts. Return a concise summary and structured IVR quality result.",
    metadata: {
      lead_id: "ivr_azul_001",
      notion_page_id: "ivr_demo_azul",
      company: "Azul",
      property: "Public customer service IVR",
      campaign: "Brazil IVR QA",
      source_url: "https://www.voeazul.com.br/br/pt/ajuda/acompanhamento-de-solicitacao"
    }
  },
  {
    callItemId: "ivr_correios_002",
    ivrName: "Correios customer service IVR",
    phone: "40038212",
    region: "BR",
    locale: "pt-BR",
    task: "Call the public Correios customer service IVR in Brazil. This is an IVR quality recording sample. Do not enter personal data, do not attempt authentication, do not open a customer case, and do not request a human agent. Listen to the opening IVR/menu for up to 90 seconds. Record whether the IVR connected, detected language, menu clarity, audio quality, latency, interruptions, DTMF or speech prompts, and any transfer or retry prompts. Return a concise summary and structured IVR quality result.",
    metadata: {
      lead_id: "ivr_correios_002",
      notion_page_id: "ivr_demo_correios",
      company: "Correios",
      property: "Public customer service IVR",
      campaign: "Brazil IVR QA",
      source_url: "https://www.correios.com.br/falecomoscorreios"
    }
  }
];

return callTasks.map((callTask) => ({
  json: {
    ...callTask,
    metadataSent: callTask.metadata,
    calleConfig: config
  }
}));

const resultSchema = {
  type: "object",
  required: ["ivr_reachable", "call_quality", "summary", "next_action"],
  properties: {
    ivr_reachable: {
      type: "string",
      enum: ["yes", "no", "unknown"]
    },
    call_quality: {
      type: "string",
      enum: ["good", "fair", "poor", "unknown"]
    },
    summary: { type: "string" },
    next_action: {
      type: "string",
      enum: ["pass", "retry_later", "manual_review"]
    },
    language_detected: { type: "string" },
    menu_summary: { type: "string" },
    audio_issues: { type: "string" },
    latency_or_interruption_notes: { type: "string" },
    dtmf_or_speech_prompt_notes: { type: "string" }
  }
};

const recipientResultSchema = {
  type: "object",
  required: ["ivr_reachable", "call_quality", "summary", "next_action"],
  properties: resultSchema.properties
};

return $input.all().map((item) => {
  const { calleConfig, metadata, metadataSent, ...callTask } = item.json;
  const metadataPayload = metadataSent || metadata || {};
  const createInput = {
    task: callTask.task,
    recipients: [
      {
        phones: [callTask.phone],
        region: callTask.region || "BR",
        locale: callTask.locale || "pt-BR"
      }
    ],
    result_schema: resultSchema,
    recipient_result_schema: recipientResultSchema,
    metadata: {
      ...metadataPayload,
      source: "n8n_two_call_task_list_sample"
    }
  };

  const idempotencyKey = [
    "n8n_list",
    metadataPayload.campaign || "campaign",
    metadataPayload.lead_id || callTask.phone,
    callTask.callItemId
  ].join("_").replace(/[^a-zA-Z0-9_-]/g, "_");

  return {
    json: {
      ...callTask,
      calleConfig,
      metadataSent: createInput.metadata,
      createInput,
      idempotencyKey
    }
  };
});

const terminalStatuses = new Set(["completed", "failed", "canceled"]);

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function requestJson(url, options) {
  const response = await helpers.httpRequest({
    url,
    method: options.method,
    headers: options.headers,
    body: options.body,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  const statusCode = response.statusCode;
  const body = response.body;

  if (statusCode < 200 || statusCode >= 300) {
    throw new Error(`CALL-E API request failed: ${statusCode} ${response.statusMessage || ""} ${JSON.stringify(body)}`);
  }

  return body;
}

async function createAndWaitForCurrentItem(item) {
  const { calleConfig, createInput, idempotencyKey, ...callTask } = item.json;
  const apiKey = calleConfig?.apiKey;

  if (!apiKey || apiKey === "replace_with_calle_api_key") {
    throw new Error("CALL-E API key is missing. Open the CALL-E Config node and replace apiKey before running this workflow.");
  }

  const baseUrl = (calleConfig?.baseUrl || "https://api.heycall-e.com").replace(/\/$/, "");
  const pollIntervalMs = Math.max(1, Number(calleConfig?.pollIntervalSeconds || 5)) * 1000;
  const timeoutMs = Math.max(1, Number(calleConfig?.waitTimeoutMinutes || 30)) * 60 * 1000;
  const startedAtMs = Date.now();
  let pollCount = 0;

  const headers = {
    "Accept": "application/json",
    "Authorization": `Bearer ${apiKey}`,
    "Content-Type": "application/json"
  };

  if (idempotencyKey) {
    headers["Idempotency-Key"] = idempotencyKey;
  }

  try {
    let call = await requestJson(`${baseUrl}/v1/calls`, {
      method: "POST",
      headers,
      body: createInput
    });

    while (!terminalStatuses.has(call.status)) {
      if (Date.now() - startedAtMs >= timeoutMs) {
        throw new Error(`Timed out waiting for CALL-E call ${call.id} after ${timeoutMs}ms.`);
      }

      await sleep(pollIntervalMs);
      pollCount += 1;
      call = await requestJson(`${baseUrl}/v1/calls/${call.id}`, {
        method: "GET",
        headers
      });
    }

    return {
      json: {
        ...callTask,
        createInput,
        ok: true,
        idempotencyKey,
        pollCount,
        rawCallResult: call,
        apiError: null
      }
    };
  } catch (error) {
    return {
      json: {
        ...callTask,
        createInput,
        ok: false,
        idempotencyKey,
        pollCount,
        rawCallResult: null,
        apiError: {
          message: error.message,
          name: error.name || "Error"
        }
      }
    };
  }
}

return await Promise.all($input.all().map((item) => createAndWaitForCurrentItem(item)));

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : null;
}

function normalizeCode(value) {
  return String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
}

function latest(values) {
  return values.length > 0 ? values[values.length - 1] : null;
}

return $input.all().map((item) => {
  const call = asObject(item.json.rawCallResult);
  const recipient = latest(asArray(call?.recipients));
  const attempts = asArray(recipient?.attempts);
  const latestAttempt = latest(attempts);
  const transcriptTurns = attempts.flatMap((attempt) => asArray(attempt.transcript_turns));
  const structuredResult = asObject(recipient?.structured_result) || asObject(call?.structured_result) || null;
  const rawFailureCode = latestAttempt?.failure_code || call?.failure_code || null;
  const failureCode = normalizeCode(rawFailureCode);
  const callStatus = call?.status || null;
  const recipientStatus = recipient?.status || null;
  const latestAttemptStatus = latestAttempt?.status || null;
  const answered = latestAttemptStatus === "completed" || recipientStatus === "completed";
  const noAnswer = failureCode === "no_answer";
  const busy = failureCode === "busy";
  const failed = Boolean(item.json.apiError) || callStatus === "failed" || recipientStatus === "failed" || latestAttemptStatus === "failed";

  return {
    json: {
      ...item.json,
      callId: call?.id || null,
      callStatus,
      recipientStatus,
      latestAttemptStatus,
      failureCode: rawFailureCode,
      failureMessage: latestAttempt?.failure_message || call?.failure_message || null,
      metadataReturned: asObject(call?.metadata) || {},
      summary: structuredResult?.summary || recipient?.summary || call?.summary || latestAttempt?.summary || null,
      transcriptTurns,
      structuredResult,
      statusSignals: {
        answered,
        no_answer: noAnswer,
        busy,
        failed
      },
      taskCompleted: call?.task_completed ?? null,
      completionConfidence: call?.completion_confidence ?? null,
      evidence: asArray(call?.evidence)
    }
  };
});

const metadataKeys = ["lead_id", "notion_page_id", "company", "property", "campaign"];

return $input.all().map((item) => {
  const result = item.json;
  const metadataSent = result.metadataSent || {};
  const metadataReturned = result.metadataReturned || {};
  const missingReturnedMetadata = metadataKeys.filter((key) => metadataSent[key] !== metadataReturned[key]);

  return {
    json: {
      callItemId: result.callItemId,
      phone: result.phone,
      task: result.task,
      metadataSent,
      metadataReturned,
      metadataRoundTrip: {
        requestedKeys: metadataKeys,
        allRequestedKeysReturned: missingReturnedMetadata.length === 0,
        missingOrDifferentKeys: missingReturnedMetadata
      },
      callStatus: {
        ok: result.ok,
        callId: result.callId,
        call_status: result.callStatus,
        recipient_status: result.recipientStatus,
        latest_attempt_status: result.latestAttemptStatus,
        failure_code: result.failureCode,
        failure_message: result.failureMessage,
        answered: result.statusSignals?.answered || false,
        no_answer: result.statusSignals?.no_answer || false,
        busy: result.statusSignals?.busy || false,
        failed: result.statusSignals?.failed || false
      },
      returnedData: {
        summary: result.summary,
        transcript: result.transcriptTurns,
        structuredResult: result.structuredResult
      },
      rawCallResult: result.rawCallResult,
      apiError: result.apiError
    }
  };
});

const items = $input.all();

return [
  {
    json: {
      processedCount: items.length,
      successfulCount: items.filter((item) => item.json.callStatus?.ok).length,
      failedCount: items.filter((item) => !item.json.callStatus?.ok).length,
      results: items.map((item) => ({
        callItemId: item.json.callItemId,
        phone: item.json.phone,
        task: item.json.task,
        metadataSent: item.json.metadataSent,
        metadataReturned: item.json.metadataReturned,
        metadataRoundTrip: item.json.metadataRoundTrip,
        callStatus: item.json.callStatus,
        returnedData: item.json.returnedData
      }))
    }
  }
];
